// The AI-disclosure line spoken as the literal first turn of EVERY outbound call.
// This is a constant assembled in code, never generated by the model, never
// skippable. There is no code path that starts a call without it.
export function disclosureLine(travelerName?: string | null): string {
  const name = (travelerName || '').trim() || 'a Waypoint traveler';
  return `Hi, this is an AI assistant calling on behalf of ${name} regarding their travel booking.`;
}
